question:
Quyidagi kod ishga tushganda konsolga nima chiqadi?
```javascript
function outer() {
  let x = 10;
  return function inner() {
    console.log(x);
  };
}
const fn = outer();
fn();
```

Quyidagi kodda konsolga nima chiqadi?
```javascript
function makeCounter() {
  let count = 0;
  return () => ++count;
}
const c1 = makeCounter();
const c2 = makeCounter();
console.log(c1());
console.log(c1());
console.log(c2());
```

Quyidagi kod bajarilganda konsolga nima chiqadi?
```javascript
let a = 5;
function printA() {
  console.log(a);
}
function test() {
  let a = 10;
  printA();
}
test();
```

